  1	import { readFileSync } from "node:fs";
  2	import { resolve } from "node:path";
  3	
  4	import {
  5	  compareReports,
  6	  type EvalComparisonRow,
  7	  type EvalReport,
  8	} from "../../src/evals/runner/report.js";
  9	
 10	type ThresholdSpec = {
 11	  readonly percent?: number;
 12	  readonly ms?: number;
 13	};
 14	
 15	type ThresholdConfig = {
 16	  readonly default: ThresholdSpec;
 17	  readonly [metric: string]: ThresholdSpec | string | undefined;
 18	};
 19	
 20	const baselinePath =
 21	  process.argv[2] ?? "tests/eval-baselines/mock-baseline.json";
 22	const candidatePath =
 23	  process.argv[3] ?? "runs/evals/ci-mock-baseline/report.json";
 24	const thresholdsPath =
 25	  process.argv[4] ?? "tests/eval-baselines/thresholds.json";
 26	
 27	const readReport = (path: string): EvalReport => {
 28	  const raw = JSON.parse(readFileSync(resolve(path), "utf8")) as Record<
 29	    string,
 30	    unknown
 31	  >;
 32	  const { _baseline: _ignored, ...report } = raw;
 33	  return report as EvalReport;
 34	};
 35	
 36	const readThresholds = (path: string): ThresholdConfig => {
 37	  const raw = JSON.parse(readFileSync(resolve(path), "utf8")) as ThresholdConfig;
 38	  const { _comment: _ignored, ...thresholds } = raw;
 39	  return thresholds as ThresholdConfig;
 40	};
 41	
 42	const toleranceFor = (
 43	  thresholds: ThresholdConfig,
 44	  metric: string,
 45	  unit: EvalComparisonRow["unit"],
 46	): number => {
 47	  const spec = thresholds[metric] ?? thresholds.default;
 48	  if (typeof spec === "string") {
 49	    return unit === "percent" ? thresholds.default.percent ?? 0 : thresholds.default.ms ?? 0;
 50	  }
 51	
 52	  if (unit === "percent") {
 53	    return spec.percent ?? thresholds.default.percent ?? 0;
 54	  }
 55	
 56	  return spec.ms ?? thresholds.default.ms ?? 0;
 57	};
 58	
 59	const exceedsTolerance = (
 60	  row: EvalComparisonRow,
 61	  thresholds: ThresholdConfig,
 62	): boolean => {
 63	  if (!row.regression) {
 64	    return false;
 65	  }
 66	
 67	  return Math.abs(row.delta) > toleranceFor(thresholds, row.metric, row.unit);
 68	};
 69	
 70	const main = (): void => {
 71	  const baseline = readReport(baselinePath);
 72	  const candidate = readReport(candidatePath);
 73	  const thresholds = readThresholds(thresholdsPath);
 74	  const comparison = compareReports(baseline, candidate);
 75	  const failures = comparison.rows.filter((row) =>
 76	    exceedsTolerance(row, thresholds),
 77	  );
 78	
 79	  if (candidate.status !== "complete") {
 80	    process.stderr.write(
 81	      `eval threshold check failed: candidate status is ${candidate.status}\n`,
 82	    );
 83	    process.exitCode = 1;
 84	    return;
 85	  }
 86	
 87	  if (candidate.overall.recordCount !== baseline.overall.recordCount) {
 88	    process.stderr.write(
 89	      `eval threshold check failed: record count ${candidate.overall.recordCount} != baseline ${baseline.overall.recordCount}\n`,
 90	    );
 91	    process.exitCode = 1;
 92	    return;
 93	  }
 94	
 95	  if (failures.length > 0) {
 96	    process.stderr.write("eval threshold check failed — regressions beyond tolerance:\n");
 97	    for (const row of failures) {
 98	      const tol = toleranceFor(thresholds, row.metric, row.unit);
 99	      const unit = row.unit === "percent" ? "%" : "ms";
100	      process.stderr.write(
101	        `  ${row.segment}/${row.metric}: ${row.baseline}${unit} -> ${row.candidate}${unit} (delta ${row.delta}${unit}, tolerance ${tol}${unit})\n`,
102	      );
103	    }
104	    process.exitCode = 1;
105	    return;
106	  }
107	
108	  process.stdout.write(
109	    `eval threshold check passed (${comparison.rows.length} metrics compared, 0 regressions beyond tolerance)\n`,
110	  );
111	};
112	
113	main();

