148	const mean = (values: readonly number[]): number =>
149	  values.reduce((sum, value) => sum + value, 0) / values.length;
150	
151	const levenshtein = (left: string, right: string): number => {
152	  const rows = left.length + 1;
153	  const cols = right.length + 1;
154	  const matrix: number[][] = Array.from({ length: rows }, () =>
155	    Array.from({ length: cols }, () => 0),
156	  );
157	
158	  for (let row = 0; row < rows; row += 1) {
159	    matrix[row]![0] = row;
160	  }
161	  for (let col = 0; col < cols; col += 1) {
162	    matrix[0]![col] = col;
163	  }
164	
165	  for (let row = 1; row < rows; row += 1) {
166	    for (let col = 1; col < cols; col += 1) {
167	      const cost = left[row - 1] === right[col - 1] ? 0 : 1;
168	      matrix[row]![col] = Math.min(
169	        (matrix[row - 1]![col] ?? 0) + 1,
170	        (matrix[row]![col - 1] ?? 0) + 1,
171	        (matrix[row - 1]![col - 1] ?? 0) + cost,
172	      );
173	    }
174	  }
175	
176	  return matrix[left.length]![right.length] ?? 0;
177	};
178	
179	const multisetJaccard = (left: readonly string[], right: readonly string[]): number => {
180	  const leftCounts = new Map<string, number>();
181	  const rightCounts = new Map<string, number>();
182	
183	  for (const tag of left) {
184	    leftCounts.set(tag, (leftCounts.get(tag) ?? 0) + 1);
185	  }
186	  for (const tag of right) {
187	    rightCounts.set(tag, (rightCounts.get(tag) ?? 0) + 1);
188	  }
189	
190	  const tags = new Set([...leftCounts.keys(), ...rightCounts.keys()]);
191	  let intersection = 0;
192	  let union = 0;
193	
194	  for (const tag of tags) {
195	    const leftCount = leftCounts.get(tag) ?? 0;
196	    const rightCount = rightCounts.get(tag) ?? 0;
197	    intersection += Math.min(leftCount, rightCount);
198	    union += Math.max(leftCount, rightCount);
199	  }
200	
201	  return union === 0 ? 0 : intersection / union;
202	};

