133	export const runEvalSuite = async (
134	  configInput: EvalRunnerConfig,
135	): Promise<EvalRunnerResult> => {
136	  validateRunnerConfig(configInput);
137	
138	  const fs = configInput.fs ?? nodeArtifactFsAdapter;
139	  const startedAt = configInput.startedAt ?? new Date().toISOString();
140	  const evalDir = `${trimTrailingSlash(configInput.rootDir)}/${configInput.evalId}`;
141	  const providerModelId = modelIdForMode(configInput.mode);
142	  const cells: EvalCellRun[] = [];
143	  let attemptedCalls = 0;
144	  let completedCalls = 0;
145	  let status: EvalRunStatus = "complete";
146	  let partialReason: string | undefined;
147	
148	  for (const cell of configInput.cells) {
149	    const records: GenerationRecord[] = [];
150	    const generationRunIds: string[] = [];
151	    const bankSeeds: PersonaBankSeed[] = [];
152	    const metricInputs: EvalMetricInput[] = [];
153	    const cellId = cellIdFor(cell.band, cell.persona);
154	
155	    for (let generationIndex = 0; generationIndex < configInput.n; generationIndex += 1) {
156	      if (attemptedCalls >= configInput.maxCalls) {
157	        status = "partial";
158	        partialReason = `call cap ${configInput.maxCalls} reached before ${cellId} generation ${generationIndex + 1}`;
159	        break;
160	      }
161	
162	      attemptedCalls += 1;
163	
164	      const bankSeed = bankSeedForIndex(generationIndex);
165	      const generationRunId = generationRunIdFor({
166	        evalId: configInput.evalId,
167	        persona: cell.persona,
168	        band: cell.band,
169	        generationIndex,
170	      });
171	      const seed = `${generationRunId}:seed`;
172	      const trace = parseTraceNdjson(
173	        readPersonaBankFixture(cell.persona, bankSeed),
174	      );
175	      const traceFacts = summarizeTrace(trace, { band: cell.band });
176	      const prompt = assemblePrompt({
177	        band: cell.band,
178	        depth: cell.depth,
179	        config,
180	        bounds,
181	        traceFacts,
182	        runContext: { seed, runId: generationRunId },
183	      });
184	      const provider = (
185	        configInput.providerFactory ?? defaultProviderFactory
186	      )({
187	        mode: configInput.mode,
188	        persona: cell.persona,
189	        band: cell.band,
190	        depth: cell.depth,
191	        seed,
192	        generationIndex,
193	      });
194	
195	      await generateFloor({
196	        prompt,
197	        provider,
198	        runId: generationRunId,
199	        depth: cell.depth,
200	        seed,
201	        modelId: providerModelId,
202	        artifacts: { rootDir: evalDir, fs },
203	        repairCap: 0,
204	      });
205	
206	      const record = loadGenerationChain(generationRunId, cell.depth, {
207	        rootDir: evalDir,
208	        fs,
209	      });
210	      records.push(record);
211	      metricInputs.push({
212	        manifest: manifestFromGenerationRecord(record, {
213	          rootDir: evalDir,
214	          fs,
215	        }),
216	        traceFacts: traceFacts.facts,
217	      });
218	      generationRunIds.push(generationRunId);
219	      bankSeeds.push(bankSeed);
220	      completedCalls += 1;
221	    }
222	
223	    cells.push({
224	      ...cell,
225	      cellId,
226	      generationRunIds,
227	      bankSeeds,
228	      records,
229	      metricInputs,
230	    });
231	
232	    if (status === "partial") {
233	      break;
234	    }
235	  }
236	
237	  const completedAt = configInput.completedAt ?? new Date().toISOString();
238	  const report = composeEvalReport({
239	    evalId: configInput.evalId,
240	    status,

240	    status,
241	    ...(partialReason === undefined ? {} : { partialReason }),
242	    startedAt,
243	    completedAt,
244	    config: configSnapshot(configInput),
245	    provider: {
246	      mode: configInput.mode,
247	      modelId: providerModelId,
248	    },
249	    bank: bankSnapshot(configInput.cells),
250	    gitRev: configInput.gitRev ?? readGitRev(),
251	    calls: {
252	      attempted: attemptedCalls,
253	      completed: completedCalls,
254	      cap: configInput.maxCalls,
255	    },
256	    cells,
257	  });
258	  const paths = writeEvalReport(report, {
259	    rootDir: configInput.rootDir,
260	    fs,
261	  });
262	
263	  return {
264	    report,
265	    reportJsonPath: paths.jsonPath,
266	    reportMarkdownPath: paths.markdownPath,
267	  };
268	};
