165	const RATE_METRICS = [
166	  "validity",
167	  "solvability",
168	  "servedWithoutFallback",
169	  "fallback",
170	  "bandAccuracy",
171	] as const;
172	
173	type RateMetric = (typeof RATE_METRICS)[number];
174	
175	export const composeEvalReport = (
176	  input: ComposeEvalReportInput,
177	): EvalReport => {
178	  const fallbackPack = loadFallbackContentPack();
179	  const cells = input.cells.map((cell) => {
180	    const thesis = scoreCellThesisMetrics(cell, fallbackPack);
181	
182	    return {
183	      cellId: cell.cellId,
184	      persona: cell.persona,
185	      band: cell.band,
186	      depth: cell.depth,
187	      generationRunIds: cell.generationRunIds,
188	      bankSeeds: cell.bankSeeds,
189	      scores: scoreGenerationRecords(cell.records, {
190	        comparability: { segmentId: cell.cellId },
191	      }),
192	      thesis,
193	    };
194	  });
195	  const records = input.cells.flatMap((cell) => [...cell.records]);
196	  const thesis = aggregateThesisSummaries(cells.map((cell) => cell.thesis.summary));
197	
198	  return {
199	    recordType: "eval-report",
200	    reportVersion: EVAL_REPORT_VERSION,
201	    evalId: input.evalId,
202	    status: input.status,
203	    ...(input.partialReason === undefined
204	      ? {}
205	      : { partialReason: input.partialReason }),
206	    startedAt: input.startedAt,
207	    completedAt: input.completedAt,
208	    config: input.config,
209	    provider: input.provider,
210	    bank: input.bank,
211	    git: { rev: input.gitRev },
212	    calls: input.calls,
213	    cells,
214	    overall: scoreGenerationRecords(records, {
215	      comparability: { candidateId: input.evalId },
216	    }),
217	    thesis,
218	  };
219	};
