241	export const scoreCellThesisMetrics = (
242	  cell: EvalCellRun,
243	  fallbackPack = loadFallbackContentPack(),
244	): EvalCellReport["thesis"] => {
245	  const inputs =
246	    cell.metricInputs ??
247	    cell.records.map(() => ({
248	      manifest: null,
249	      traceFacts: emptyTraceFacts(),
250	    }));
251	  const recentManifests: FloorManifest[] = [];
252	  const generations: EvalGenerationThesisScore[] = [];
253	
254	  for (const [generationIndex, input] of inputs.entries()) {
255	    const manifest = input.manifest;
256	    const novelty =
257	      manifest === null
258	        ? null
259	        : noveltyDistance(manifest, {
260	            fallbackPack,
261	            recentManifests: [...recentManifests],
262	          });
263	    const responsiveness =
264	      manifest === null
265	        ? null
266	        : responsivenessMatrix(manifest, input.traceFacts, cell.persona);
267	
268	    if (manifest !== null) {
269	      recentManifests.push(manifest);
270	    }
271	
272	    generations.push({
273	      generationIndex,
274	      novelty,
275	      responsiveness,
276	    });
277	  }
278	
279	  return {
280	    generations,
281	    summary: summarizeThesisGenerations(generations, cell.persona),
282	  };
283	};
