285	const summarizeThesisGenerations = (
286	  generations: readonly EvalGenerationThesisScore[],
287	  persona: PersonaName,
288	): EvalThesisSummary => {
289	  const noveltyScores = generations
290	    .map((generation) => generation.novelty?.score ?? null)
291	    .filter((score): score is number => score !== null);
292	  const nearDuplicateCount = generations.filter(
293	    (generation) => generation.novelty?.nearDuplicate === true,
294	  ).length;
295	  const samePersonaRates = generations
296	    .map((generation) => generation.responsiveness?.samePersona.rate ?? null)
297	    .filter((rate): rate is number => rate !== null);
298	  const crossPersonaRates = generations.flatMap((generation) => {
299	    if (generation.responsiveness === null) {
300	      return [];
301	    }
302	
303	    return Object.entries(generation.responsiveness.crossPersona)
304	      .filter(([targetPersona]) => targetPersona !== persona)
305	      .map(([, hitRate]) => hitRate.rate);
306	  });
307	
308	  return {
309	    novelty: {
310	      averageScore:
311	        noveltyScores.length === 0
312	          ? 0
313	          : noveltyScores.reduce((sum, score) => sum + score, 0) /
314	            noveltyScores.length,
315	      nearDuplicateCount,
316	      sampleCount: noveltyScores.length,
317	    },
318	    responsiveness: {
319	      samePersonaHitRate:
320	        samePersonaRates.length === 0
321	          ? 0
322	          : samePersonaRates.reduce((sum, rate) => sum + rate, 0) /
323	            samePersonaRates.length,
324	      crossPersonaHitRate:
325	        crossPersonaRates.length === 0
326	          ? 0
327	          : crossPersonaRates.reduce((sum, rate) => sum + rate, 0) /
328	            crossPersonaRates.length,
329	      sampleCount: samePersonaRates.length,
330	    },
331	    detectorProposal: serializeDetectorProposal(),
332	  };
333	};
